parameters.text:
=Analyze the following patient intake information and perform triage.

Patient Name: {{$json.patient_name}}

Age: {{$json.age}}

Gender: {{$json.gender}}

Phone: {{$json.phone}}

Symptoms: {{$json.symptoms}}

Additional Notes: {{$json.notes}}

Please determine urgency level, recommended department, appointment priority, and recommended action.

parameters.jsCode:
// Get AI response
const raw = $json;

// Sometimes AI returns JSON as string
let data;

try {
  data = typeof raw === "string" ? JSON.parse(raw) : raw;
} catch (error) {
  data = JSON.parse(raw.output || "{}");
}

// Helper function
const safe = (value, fallback = "") => {
  if (value === undefined || value === null) return fallback;
  return String(value).trim();
};

// Normalize urgency
const normalizeUrgency = (urgency) => {
  if (!urgency) return "MEDIUM";

  const u = urgency.toLowerCase();

  if (u.includes("critical")) return "CRITICAL";
  if (u.includes("high")) return "HIGH";
  if (u.includes("medium")) return "MEDIUM";
  if (u.includes("low")) return "LOW";

  return "MEDIUM";
};

const urgency = normalizeUrgency(data.urgency_level);

// Normalize department
const department = safe(data.recommended_department, "General Physician");

// Priority mapping
let priority = "Routine";

if (urgency === "CRITICAL") priority = "Immediate";
if (urgency === "HIGH") priority = "Same Day";
if (urgency === "MEDIUM") priority = "24-48 Hours";
if (urgency === "LOW") priority = "3-5 Days";

// Normalized object
const normalized = {
  patient_name: safe(data.patient_name),
  patient_age: safe(data.patient_age),
  patient_gender: safe(data.patient_gender),
  phone: safe(data.phone),
  symptoms: safe(data.symptoms),
  symptom_duration: safe(data.symptom_duration),
  urgency_level: urgency,
  recommended_department: department,
  appointment_priority: priority,
  triage_reasoning: safe(data.triage_reasoning),
  recommended_action: safe(data.recommended_action),
  sheet_row: {
    Name: safe(data.patient_name),
    Age: safe(data.patient_age),
    Gender: safe(data.patient_gender),
    Phone: safe(data.phone),
    Symptoms: safe(data.symptoms),
    Urgency: urgency,
    Department: department,
    Priority: priority,
    "Recommended Action": safe(data.recommended_action)
  }
};

return [{ json: normalized }];

parameters.text:
=Analyze the following patient intake form and assign the most suitable doctor.

Patient Information:

Name: {{$json.name}}

Age: {{$json.age}}

Gender: {{$json.gender}}

Symptoms: {{$json.symptoms}}

Use the connected doctor sheet tool to find available doctors and their specialties.

Select the most appropriate doctor based on the symptoms.

parameters.jsCode:
// Get raw AI response
let raw = $json;

// If AI returned text containing JSON
if (typeof raw === "string") {
  try {
    raw = JSON.parse(raw);
  } catch {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) {
      raw = JSON.parse(match[0]);
    } else {
      raw = {};
    }
  }
}

// Helper functions
const clean = (value, fallback = "") => {
  if (value === undefined || value === null) return fallback;
  return String(value).trim();
};

const normalizeGender = (gender) => {
  const g = clean(gender).toLowerCase();
  if (g.includes("male")) return "Male";
  if (g.includes("female")) return "Female";
  return "Other";
};

const normalizeAge = (age) => {
  const num = parseInt(age);
  if (isNaN(num)) return "";
  return num;
};

const normalizeSpecialty = (specialty) => {
  if (!specialty) return "General Physician";

  const s = specialty.toLowerCase();

  if (s.includes("cardio")) return "Cardiologist";
  if (s.includes("derma")) return "Dermatologist";
  if (s.includes("ortho")) return "Orthopedic";
  if (s.includes("neuro")) return "Neurologist";
  if (s.includes("ent")) return "ENT Specialist";
  if (s.includes("gastro")) return "Gastroenterologist";
  if (s.includes("pulmo")) return "Pulmonologist";
  if (s.includes("gyn")) return "Gynecologist";
  if (s.includes("pedia")) return "Pediatrician";

  return "General Physician";
};

// Extract patient details
const patient = raw.patient_details || {};

// Normalize fields
const name = clean(patient.name);
const age = normalizeAge(patient.age);
const gender = normalizeGender(patient.gender);
const symptoms = clean(patient.symptoms);

const specialty = normalizeSpecialty(raw.recommended_specialty);
const doctor = clean(raw.assigned_doctor);
const reason = clean(raw.assignment_reason);

// Final normalized object
const normalized = {
  patient_name: name,
  patient_age: age,
  patient_gender: gender,
  symptoms: symptoms,
  recommended_specialty: specialty,
  assigned_doctor: doctor,
  assignment_reason: reason,

  sheet_row: {
    "Patient Name": name,
    "Age": age,
    "Gender": gender,
    "Symptoms": symptoms,
    "Specialty": specialty,
    "Doctor Assigned": doctor
  }
};

return [{ json: normalized }];

const items = $input.all();

// Extract doctor info from first record
const doctorName = items[0]?.json?.doctor_name || "Doctor";
const date = new Date().toLocaleDateString();

// Build table rows
let rows = "";

for (const item of items) {
  const a = item.json;

  rows += `
  <tr>
    <td>${a.time || "-"}</td>
    <td>${a.patient_name || "-"}</td>
    <td>${a.age || "-"}</td>
    <td>${a.gender || "-"}</td>
    <td>${a.symptoms || "-"}</td>
  </tr>
  `;
}

// HTML Email Template
